<template>
    <section id="section-one">
        <h1>Алексей <br>и Маргарита</h1>
        <h2>25.06.2025</h2>
        <div class="data-time-container">
            <div class="time-labels">
                <div class="time-labels-item">
                    <p>{{ days }}</p>
                    <p>ДНЕЙ</p>
                </div>
                <div class="time-labels-item">
                    <p>{{ hours }}</p>
                    <p>ЧАСОВ</p>
                </div>
                <div class="time-labels-item">
                    <p>{{ minutes }}</p>
                    <p>МИНУТ</p>
                </div>
                <div class="time-labels-item">
                    <p>{{ seconds }}</p>
                    <p>СЕКУНД</p>
                </div>
            </div>
        </div>
    </section>
</template>

<script>
const targetDate = new Date("2025-06-25T00:00:00Z").getTime();

export default {
    data() {
        return {
            targetDate: targetDate,
            days: 0,
            hours: 0,
            minutes: 0,
            seconds: 0,
        }
    },
    methods: {
        updateTime(){
            const now = new Date().getTime();
            const distance = this.targetDate - now;
            const formatNumber = (num) => num.toString().padStart(2, '0');
            this.days = formatNumber(Math.floor(distance / (1000 * 60 * 60 * 24)));
            this.hours = formatNumber(Math.floor((distance % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)));
            this.minutes = formatNumber(Math.floor((distance % (1000 * 60 * 60)) / (1000 * 60)));
            this.seconds = formatNumber(Math.floor((distance % (1000 * 60)) / 1000));

        }
    },
    mounted() {
        this.updateTime();
        setInterval(this.updateTime, 1000);
    },
}
</script>

<style scoped>
#section-one{
  position: relative;
  width:100%;
  height: 100vh;
  background-image: url(@/assets/hands.jpg);
  background-position: center;
  background-repeat: no-repeat;
  background-size: cover;
  background-color: rgba(0, 0, 0, 0.4);
  background-blend-mode: darken;
  text-shadow: 0px 4px 4px var(--gold);
  color: white;
  padding: 10px;
}

#section-one h1{
  font-size: 75px;
  text-align: center;
  margin-top: 20%;
  margin-bottom: 10%;
  font-weight: 100;
}

#section-one h2{
  font-size: 50px;
  text-align: center;
  margin: 0;
  font-weight: 100;
}

.data-time-container{
  backdrop-filter: blur(5px);
  position: absolute;
  width: 80%;
  bottom: 10%;
  left: 50%;
  transform: translateX(-50%);
  border-radius: 5px;
  border: 1px solid white;
  box-shadow: 0px 0px 10px 0px var(--gold);
  padding: 10px 0px;
}

.time-labels{
  display: flex;
  justify-content: space-evenly;
  align-items: center;
  width: 100%;
  text-align: center;
}

.time-labels-item{
    width:25%;
}

.time-labels-item >p:nth-child(1){
    font-size: 24px;
    padding: 5px 0px;
    margin: 0;
}

.time-labels-item >p:nth-child(2){
    padding: 0%;
    margin: 0%;
}

@media (max-width: 420px){
    #section-one h1{
        font-size: 65px;
    }
}

@media (max-width: 380px){
    #section-one h1{
        font-size: 60px;
    }
    #section-one h2{
        font-size: 40px;
    }
}
</style>