<script>
export default {
    data() {
        return {
            countPeople: 1,
            name: {
                name1: "",
                name2: "",
            },
            alcoPref: {
                champagne: false,
                wine: false,
                vodka: false,
                beer: false,
            },
            message: "",
            alcohol: '',
            attendance: ''
        }
    },
    computed: {
        enumerate() {
            return Array.from({ length: this.countPeople }, (_, i) => i + 1);
        }
    },
    methods: {
        resetForm() {
            this.countPeople = 1;
            this.name.name1 = "";
